// Parse EUR-Lex search results for new/updated CBAM regulations
const items = $input.all();

const now = new Date();
const sixHoursAgo = new Date(now.getTime() - 6 * 60 * 60 * 1000);

const cbamKeywords = [
  'CBAM', 'carbon border adjustment', 'emission trading',
  'ETS', 'carbon leakage', 'free allocation', 'benchmark',
  'verification', 'accredited verifier', 'implementing regulation',
  'delegated regulation', 'default value', 'transitional period',
  '2023/956', '2023/1773', 'Combined Nomenclature'
];

const newRegulations = [];

for (const item of items) {
  const body = item.json?.body ?? item.json?.data ?? '';
  if (typeof body !== 'string' || body.length < 100) continue;

  // Extract regulation titles via regex
  const titleRegex = /(?:Regulation|Implementing Regulation|Delegated Regulation)\s*\(EU\)\s*20\d{2}\/\d{1,5}[^<]*/gi;
  let match;
  while ((match = titleRegex.exec(body)) !== null) {
    for (const keyword of cbamKeywords) {
      if (match[0].toLowerCase().includes(keyword.toLowerCase()) ||
          body.slice(match.index - 200, match.index + 500).toLowerCase().includes(keyword.toLowerCase())) {
        newRegulations.push({
          title: match[0].trim(),
          matchedKeyword: keyword,
          snippet: body.slice(Math.max(0, match.index - 100), match.index + 400).trim(),
          detectedAt: now.toISOString(),
        });
        break;
      }
    }
  }
}

// Deduplicate by title
const seen = new Set();
const unique = newRegulations.filter(r => {
  if (seen.has(r.title)) return false;
  seen.add(r.title);
  return true;
});

console.log(`[W19] Found ${unique.length} new/updated CBAM regulations`);

if (unique.length > 0) {
  return unique.map(r => ({ json: r }));
}
return [{ json: { title: 'No new CBAM regulations in last 6 hours', status: 'clear' } }];

